+        Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
+
+    private static readonly string DataPath =
+        Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
+
+    public Task StartAsync(CancellationToken cancellationToken)
+    {
+        var mlContext = new MLContext(seed: 42);
+
+        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
+            DataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
+
+        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
+
+        var pipeline = mlContext.Transforms.Text
+            .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
+            .Append(mlContext.Transforms.Text
+                .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
+            .Append(mlContext.Transforms.NormalizeMeanVariance(
+                "PriorityNormalized", nameof(TicketInput.Priority)))
+            .Append(mlContext.Transforms.Concatenate(
+                "Features", "SubjectFeatures", "DescriptionFeatures", "PriorityNormalized"))
+            .Append(mlContext.Transforms.Conversion.MapValueToKey(
+                "Label", nameof(TicketInput.Category)))
+            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
+            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
+
+        logger.LogInformation("Training ticket classification model...");
+        var model = pipeline.Fit(split.TrainSet);
+
+        var predictions = model.Transform(split.TestSet);
+        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);
+
+        logger.LogInformation("=== Model Evaluation Metrics ===");
+        logger.LogInformation("Macro Accuracy:     {MacroAccuracy:F4}", metrics.MacroAccuracy);
+        logger.LogInformation("Micro Accuracy:     {MicroAccuracy:F4}", metrics.MicroAccuracy);
+        logger.LogInformation("Log Loss:           {LogLoss:F4}", metrics.LogLoss);
+        logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);
+        logger.LogInformation("\n{ConfusionMatrix}",
+            metrics.ConfusionMatrix.GetFormattedConfusionTable());
+
+        Directory.CreateDirectory(Path.GetDirectoryName(ModelPath)!);
+        mlContext.Model.Save(model, data.Schema, ModelPath);
+        logger.LogInformation("Model saved to {ModelPath}", ModelPath);
+
+        return Task.CompletedTask;
+    }
+
+    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
+}
